\usepackage[utf8]{inputenc}
\usepackage[T1]{fontenc}
\usepackage{lmodern}
\usepackage{booktabs}
\usepackage{multirow}
\usepackage{graphicx}
\usepackage{hyperref}

%% Theme
\usetheme{Madrid}
\usecolortheme{default}

%% Metadata
\title{Interface Design Research in Information Systems}
\subtitle{Visual Presentation, Cognition, and Decision-Making}
\author{Research Note}
\date{\today}

%% Path for figures
\graphicspath{{/Users/my/output/figures/}}

%% Document
\begin{document}

%% === Title Slide ===
\begin{frame}
\titlepage
\end{frame}

%% === Motivation: Morningstar Case ===
\begin{frame}{Motivation: A Real-World Interface Redesign}
\begin{quote}
In October 2019, Morningstar implemented a major update to its mutual fund report design, introducing color-coded Upside and Downside Capture Ratios (UCR/DCR) to make risk more visually salient. The redesign was intended to provide a more streamlined, visually appealing, and interactive interface for evaluating mutual funds, with clearer presentation of risk-related information.
\end{quote}

\vspace{0.5cm}
\begin{itemize}
\item \textbf{Visual salience} of financial risk metrics introduced through color-coding
\item Design change affects how investors process and interpret risk signals
\item Empirical question: do visual interface changes alter real financial decisions?
\end{itemize}
\end{frame}

%% === Research Question & Positioning ===
\begin{frame}{Research Question and Dual Positioning}
\begin{block}{IS Positioning}
How does platform interface design shape individuals' cognition, attention and decision-making?
\end{block}

\begin{block}{Finance Positioning}
How visual risk information affects investor beliefs and capital allocation?
\end{block}

\vspace{0.5cm}
\textbf{Current Focus:} The visual presentation of specific financial risk metrics influences investor behavior in digital platforms.
\end{frame}

%% === Research Gap ===
\begin{frame}{Research Gap}
Existing research does \textbf{NOT} study:

\begin{itemize}
\item UI redesigns by major financial platforms (like Morningstar)
\item How specific risk metrics (UCR/DCR) interact with visual encoding
\item The causal impact of visual salience (e.g., color-coded risk metrics)
\end{itemize}

\vspace{0.5cm}
\begin{alertblock}{Key Insight}
We bridge abstract visualization studies with real-world financial decision environments, linking interface design to material capital allocation.
\end{alertblock}
\end{frame}

%% === Contributions ===
\begin{frame}{Core Contributions}
\begin{enumerate}
\item \textbf{Material Impact on Cognition:} We show digital interface design materially alters risk perceptions and real capital allocation.
\item \textbf{Attention Competition:} We identify which signals win the competition for user attention in high-dimensional dashboards.
\item \textbf{Market Consequences:} We highlight unintended market consequences of digital platform design.
\end{enumerate}

\vspace{0.5cm}
\begin{block}{IS-Cognitive Lens}
Visual design elements (color, layout, visual encoding, interactivity) $\rightarrow$ Cognitive Process (attention, perception, biases) $\rightarrow$ Behavioral Output (risk perception, decision-making)
\end{block}
\end{frame}

%% === Transition Slide ===
\begin{frame}
\centering
\Huge \textbf{Literature Review: Website Design and Cognition}
\end{frame}

%% === Literature 1 ===
\begin{frame}{Website Design and Cognition (1): Visual Effects on Attention}
\textbf{Deng \& Poole (2010)} \textit{MIS Quarterly}
\begin{itemize}
\item Webpage visual complexity and order affect emotional responses and approach behavior
\item Emotional carry-over from first encounter affects subsequent engagement
\end{itemize}

\textbf{Hong, Thong \& Tam (2004)} \textit{Information Systems Research}
\begin{itemize}
\item Flash animation attracts attention but may decrease recall and attitude
\item Limited attentional resources trade-off: suppression of distraction reduces mental resources for information processing
\end{itemize}

\textbf{Speier \& Morris (2003)} \textit{MIS Quarterly}
\begin{itemize}
\item Visual interfaces improve performance under high task complexity
\item Lower subjective mental workload regardless of task complexity
\end{itemize}
\end{frame}

%% === Literature 2 ===
\begin{frame}{Website Design and Cognition (2): Visual Cues and Integration}
\textbf{Kim, Hahn \& Hahn (2000)} \textit{Information Systems Research}
\begin{itemize}
\item Perceptual and conceptual integration in diagrammatic reasoning
\item Visual cues facilitate information integration across multiple diagrams
\end{itemize}

\textbf{Cyr (2008)} \textit{Journal of Management Information Systems}
\begin{itemize}
\item Visual design influences trust, satisfaction, and e-loyalty across cultures
\item Navigation, visual design, and information design have differential effects
\end{itemize}

\textbf{Jiang et al. (2016)} \textit{JMIS}
\begin{itemize}
\item Aesthetics (unity, complexity, intensity, novelty, interactivity) determine perceived quality
\item First-impression aesthetics impacts attitudes more than perceived utility
\end{itemize}
\end{frame}

%% === Literature 3 ===
\begin{frame}{Website Design and Cognition (3): Complexity and Cognitive Fit}
\textbf{Hong, Thong \& Tam (2004)} \textit{JMIS}
\begin{itemize}
\item Cognitive fit between information format and shopping task affects efficiency \& recall
\item List format better supports browsing; matrix format facilitates searching
\end{itemize}

\textbf{Nadkarni \& Gupta (2007)} \textit{MIS Quarterly}
\begin{itemize}
\item Perceived website complexity (PWC) central to visitor experience
\item PWC-user satisfaction relationship depends on user type (goal-directed vs experiential)
\end{itemize}

\textbf{Hu, Hu \& Fang (2017)} \textit{MIS Quarterly}
\begin{itemize}
\item Navigation structure and user familiarity affect satisfaction via performance and cognitive load
\item Cognitive load affects satisfaction more than performance outcomes
\end{itemize}
\end{frame}

%% === Transition ===
\begin{frame}
\centering
\Huge \textbf{Literature Review: Information, Marketing \& Actions Support}
\end{frame}

%% === Literature 4 ===
\begin{frame}{Information, Marketing \& Actions Support}
\textbf{Benbasat \& Dexter (1985)} \textit{Management Science}
\begin{itemize}
\item Color-enhanced information presentation improves decision quality, especially for field-dependent individuals
\end{itemize}

\textbf{Dennis et al. (2020)} \textit{JMIS}
\begin{itemize}
\item Digital nudging via numeric and semantic priming in e-commerce
\item Priming affects willingness to pay when product value is unclear
\end{itemize}

\textbf{Li et al. (2023)} \textit{Management Science}
\begin{itemize}
\item Airbnb photo layout (room type, quality, order) materially influences renting decisions
\item Optimal photo layout can increase bookings by $\sim$11\% and boost revenue
\end{itemize}

\textbf{Pieters, Wedel \& Zhang (2007)} \textit{Management Science}
\begin{itemize}
\item Optimization of feature ad design to capture consumer attention in competitive clutter
\item Visual entropy measures characterize salience in competitive environments
\end{itemize}
\end{frame}

%% === Literature 5 ===
\begin{frame}{Visual Analytics and Social Media}
\textbf{Shin et al. (2020)} \textit{MIS Quarterly}
\begin{itemize}
\item Visual data analytics framework for social media research using deep learning
\item Visual and textual content features (complexity, similarity, consistency) predict post popularity
\end{itemize}

\textbf{Dou et al. (2010)} \textit{MIS Quarterly}
\begin{itemize}
\item Search engine result page order activates implicit beliefs (schema)
\item Displaying unknown brand before well-known brands improves recall for low-skill users
\end{itemize}

\textbf{Sim et al. (2024)} \textit{MIS Quarterly}
\begin{itemize}
\item In-consumption information cues (visual progress bars, engagement graphs) enhance viewership
\item ICICs increase immersion but may not directly affect virtual gift donations
\end{itemize}
\end{frame}

%% === Transition ===
\begin{frame}
\centering
\Huge \textbf{Neurophysiological Approaches}
\end{frame}

%% === Literature 6 ===
\begin{frame}{Neurophysiological Approaches}
\textbf{Lakhiwal, Bala \& Léger (2023)} \textit{MIS Quarterly}
\begin{itemize}
\item Ambivalence (mixed ratings) vs indifference in online environments
\item EEG study: ambivalence and indifference distinctly influence attention and purchase decisions
\item Star rating systems cannot capture mixed feelings
\end{itemize}

\textbf{Vance et al. (2025)} \textit{MIS Quarterly}
\begin{itemize}
\item Generalization of habituation explains why users disregard security warnings
\item fMRI study: habituation transfers unconsciously at neurobiological level
\item Differentiating warnings from notifications via visual appearance or interaction mitigates habituation
\end{itemize}

\textbf{Meservy et al. (2019)} \textit{MIS Quarterly}
\begin{itemize}
\item fMRI exploration of content vs contextual cues in forum filtering
\item Community-based cues factor more heavily than expert-based cues
\item Distinct neural activation patterns for specific cue combinations
\end{itemize}
\end{frame}

%% === Transition ===
\begin{frame}
\centering
\Huge \textbf{Finance Positioning: Visual Risk Metrics}
\end{frame}

%% === Finance Literature ===
\begin{frame}{Finance Positioning: Visual Risk Metrics}
\textbf{Visual Finance: The Pervasive Effects of Red on Investor Behavior} \textit{Management Science (2021)}
\begin{itemize}
\item Color influences investor decisions in finance contexts
\end{itemize}

\textbf{Obaid \& Pukthuanthong (2022)} \textit{JFE}
\begin{itemize}
\item Measuring investor sentiment by combining machine learning and photos from news
\end{itemize}

\textbf{Grant, Hobson \& Sinha (2024)} \textit{Management Science}
\begin{itemize}
\item Digital engagement in mobile trading: impact of color and swipe-to-trade on investor decisions
\end{itemize}

\textbf{Cardinaels, Kramer \& Maas (2024)} \textit{Contemporary Accounting Research}
\begin{itemize}
\item Color-coded performance feedback effects on decision-making
\end{itemize}

\textbf{Fisher (2021, 2023)} \textit{Management Science}
\begin{itemize}
\item Visual attention causally influences intertemporal choices and decision-making
\item Measuring factors influencing purchasing decisions via cursor tracking and cognitive modeling
\end{itemize}
\end{frame}

